import React, { useState, useEffect } from 'react';
import axios from 'axios';
import TopNavBar from './components/TopNavBar';
import Hero from './components/Hero';
import MovieCard from './components/MovieCard';
import './index.css';

function App() {
  const [movie, setMovie] = useState('');
  const [primaryMovie, setPrimaryMovie] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [visibleCount, setVisibleCount] = useState(20);

  const fetchRecommendations = async (e) => {
    if (e) e.preventDefault();
    if (!movie.trim()) return;

    setLoading(true);
    setError('');
    setVisibleCount(20);

    try {
      const response = await axios.post('http://127.0.0.1:5000/recommend', {
        movie: movie,
        get_1000: true
      });

      setPrimaryMovie(response.data.primary);
      setRecommendations(response.data.recommendations || []);
      // Scroll to top when searching
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
      console.error(err);
      if (err.response && err.response.status === 404) {
        setError("Movie not found. Try 'Inception' or 'The Matrix'.");
      } else {
        setError('Backend not responding. Run python app.py.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleLoadMore = () => {
    setVisibleCount(prev => prev + 20);
  };

  return (
    <div className="bg-surface text-on-surface font-body selection:bg-primary-container selection:text-on-primary-container relative min-h-screen">
      {/* Background Layer */}
      <div className="ambient-bg">
        <div className="orb orb-1"></div>
        <div className="orb orb-2"></div>
        <div className="orb orb-3"></div>
        <div className="light-leak"></div>
      </div>

      <TopNavBar 
        onSearch={fetchRecommendations} 
        movie={movie} 
        setMovie={setMovie} 
        loading={loading}
      />

      <main className="pb-24 relative z-10 transition-all duration-500">
        <Hero movie={primaryMovie} />

        {/* Dynamic Recommendations Section */}
        <section className={`px-8 space-y-8 ${primaryMovie ? 'mt-12' : 'mt-[-100px]'} relative z-20`}>
          <div className="flex justify-between items-end">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <span className="material-symbols-outlined text-primary-fixed-dim scale-75">auto_awesome</span>
                <h2 className="font-headline text-2xl font-bold tracking-tight">
                  {primaryMovie ? `More Like ${primaryMovie.title}` : "AI Predicted Favorites"}
                </h2>
              </div>
              <p className="text-neutral-500 text-sm">
                Curated based on deep architectural themes and narrative patterns.
              </p>
            </div>
            {recommendations.length > visibleCount && (
              <button 
                onClick={handleLoadMore}
                className="text-primary-fixed-dim text-sm font-semibold hover:underline"
              >
                Load More
              </button>
            )}
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-6">
            {recommendations.slice(0, visibleCount).map((rec, index) => (
              <MovieCard key={index} movie={rec} />
            ))}
          </div>

          {error && (
            <div className="flex justify-center mt-8">
              <div className="bg-error-container/20 text-error px-6 py-4 rounded-xl border border-error/20 backdrop-blur-md">
                {error}
              </div>
            </div>
          )}
        </section>

        {/* Footer */}
        <footer className="mt-24 bg-neutral-900/50 backdrop-blur-md border-t border-neutral-800/50 w-full py-12 px-8">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
            <div className="flex flex-col items-center md:items-start gap-2">
              <span className="text-lg font-bold text-neutral-200 font-headline tracking-tighter">CINE-AI</span>
              <p className="font-inter text-xs uppercase tracking-widest text-neutral-500">© 2024 CINE-AI. Built with AI.</p>
            </div>
            <div className="flex gap-8">
              <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors" href="#">Help Center</a>
              <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors" href="#">Privacy Policy</a>
              <a className="font-inter text-xs uppercase tracking-widest text-neutral-500 hover:text-red-500 transition-colors" href="#">Terms</a>
            </div>
          </div>
        </footer>
      </main>

      {/* Mobile Nav */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-neutral-950/90 backdrop-blur-2xl px-6 py-3 flex justify-between items-center">
        <button className="flex flex-col items-center gap-1 text-white">
          <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>home</span>
          <span className="text-[10px] font-bold">Browse</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-neutral-400">
          <span className="material-symbols-outlined">explore</span>
          <span className="text-[10px]">Explore</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-neutral-400">
          <span className="material-symbols-outlined">account_circle</span>
          <span className="text-[10px]">Profile</span>
        </button>
      </nav>
    </div>
  );
}

export default App;
